/**
 * MarketDataDownloadPanel -- Download Market Data UI
 *
 * Shows cache status, disk usage, and allows downloading additional symbols
 * beyond the bundled defaults. Works in both Tauri (via invoke) and web (via API).
 */
import { useState, useEffect, useCallback, useRef } from 'react';
import { getApiBase } from '../utils/platform';
import { isTauri } from '../utils/platform';

// ── Helpers ─────────────────────────────────────────────────────────────────
function formatBytes(bytes) {
  if (!bytes || bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return `${(bytes / Math.pow(k, i)).toFixed(1)} ${sizes[i]}`;
}

function timeAgo(ts) {
  if (!ts) return 'never';
  const diff = Date.now() - new Date(ts).getTime();
  const secs = Math.floor(diff / 1000);
  if (secs < 0) return 'just now';
  if (secs < 60) return `${secs}s ago`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

function freshnessColor(ts) {
  if (!ts) return '#8B949E';
  const hrs = (Date.now() - new Date(ts).getTime()) / 3600000;
  if (hrs < 1) return '#22C55E';
  if (hrs < 24) return '#60A5FA';
  if (hrs < 72) return '#F59E0B';
  return '#EF4444';
}

// ── Main Component ──────────────────────────────────────────────────────────
export default function MarketDataDownloadPanel() {
  const [cacheStatus, setCacheStatus] = useState(null);
  const [loading, setLoading] = useState(true);
  const [downloading, setDownloading] = useState(false);
  const [downloadProgress, setDownloadProgress] = useState(0);
  const [downloadSymbol, setDownloadSymbol] = useState('');
  const [symbolInput, setSymbolInput] = useState('');
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const mountedRef = useRef(true);

  // Fetch cache status
  const fetchCacheStatus = useCallback(async () => {
    try {
      let data;
      // Tauri desktop: try window.__TAURI_INTERNALS__ invoke if available
      if (isTauri() && window.__TAURI_INTERNALS__?.invoke) {
        try {
          data = await window.__TAURI_INTERNALS__.invoke('get_cache_status');
        } catch {
          // Tauri command not available, fall through to API
        }
      }
      // Fallback (or primary for web): use API endpoint
      if (!data) {
        const resp = await fetch(`${getApiBase()}/data/cache/status`, {
          headers: {
            Authorization: `Bearer ${localStorage.getItem('aura_token') || ''}`,
          },
        });
        if (resp.ok) data = await resp.json();
      }

      if (mountedRef.current && data) {
        setCacheStatus(data);
        setError(null);
      }
    } catch (err) {
      if (mountedRef.current) {
        setError('Unable to fetch cache status');
      }
    } finally {
      if (mountedRef.current) setLoading(false);
    }
  }, []);

  useEffect(() => {
    mountedRef.current = true;
    fetchCacheStatus();
    const iv = setInterval(fetchCacheStatus, 30000);
    return () => {
      mountedRef.current = false;
      clearInterval(iv);
    };
  }, [fetchCacheStatus]);

  // Download symbols
  const handleDownload = useCallback(async () => {
    const symbols = symbolInput
      .split(/[,\s]+/)
      .map(s => s.trim().toUpperCase())
      .filter(Boolean);

    if (symbols.length === 0) {
      setError('Enter at least one symbol');
      return;
    }

    setDownloading(true);
    setDownloadProgress(0);
    setError(null);
    setSuccess(null);

    try {
      for (let i = 0; i < symbols.length; i++) {
        const sym = symbols[i];
        if (mountedRef.current) {
          setDownloadSymbol(sym);
          setDownloadProgress(Math.round(((i) / symbols.length) * 100));
        }

        let downloaded = false;
        // Tauri desktop: try invoke if available
        if (isTauri() && window.__TAURI_INTERNALS__?.invoke) {
          try {
            await window.__TAURI_INTERNALS__.invoke('download_symbol_data', { symbol: sym });
            downloaded = true;
          } catch {
            // Tauri command not available, fall through to API
          }
        }
        // Fallback (or primary for web): use API endpoint
        if (!downloaded) {
          await fetch(`${getApiBase()}/data/cache/refresh`, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              Authorization: `Bearer ${localStorage.getItem('aura_token') || ''}`,
            },
            body: JSON.stringify({ symbols: [sym] }),
          });
        }
      }

      if (mountedRef.current) {
        setDownloadProgress(100);
        setSuccess(`Downloaded data for ${symbols.length} symbol${symbols.length > 1 ? 's' : ''}`);
        setSymbolInput('');
        // Refresh cache status
        setTimeout(fetchCacheStatus, 1000);
      }
    } catch (err) {
      if (mountedRef.current) {
        setError(`Download failed: ${err.message || 'Unknown error'}`);
      }
    } finally {
      if (mountedRef.current) {
        setDownloading(false);
        setDownloadSymbol('');
      }
    }
  }, [symbolInput, fetchCacheStatus]);

  // Styles
  const panel = {
    background: 'var(--color-surface, #0F1620)',
    border: '1px solid var(--color-border, rgba(255,255,255,0.06))',
    borderRadius: 12,
    padding: 20,
  };

  const heading = {
    fontSize: 14,
    fontWeight: 700,
    color: 'var(--color-text, #E5E7DB)',
    marginBottom: 16,
    display: 'flex',
    alignItems: 'center',
    gap: 8,
  };

  const statGrid = {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))',
    gap: 12,
    marginBottom: 16,
  };

  const statCard = {
    background: 'var(--color-bg, #0B0F14)',
    border: '1px solid var(--color-border, rgba(255,255,255,0.06))',
    borderRadius: 8,
    padding: '12px 14px',
    display: 'flex',
    flexDirection: 'column',
    gap: 4,
  };

  const statLabel = {
    fontSize: 10,
    fontWeight: 600,
    color: 'var(--color-text-secondary, #90A3AF)',
    textTransform: 'uppercase',
    letterSpacing: 0.5,
  };

  const statValue = {
    fontSize: 18,
    fontWeight: 700,
    fontFamily: "'JetBrains Mono', monospace",
    color: 'var(--color-text, #E5E7DB)',
  };

  const inputRow = {
    display: 'flex',
    gap: 8,
    marginTop: 12,
  };

  const input = {
    flex: 1,
    background: 'var(--color-bg, #0B0F14)',
    border: '1px solid var(--color-border, rgba(255,255,255,0.06))',
    borderRadius: 8,
    padding: '8px 12px',
    color: 'var(--color-text, #E5E7DB)',
    fontSize: 13,
    fontFamily: "'JetBrains Mono', monospace",
    outline: 'none',
  };

  const btn = {
    background: downloading ? 'rgba(96,165,250,0.15)' : 'rgba(96,165,250,0.2)',
    color: '#60A5FA',
    border: '1px solid rgba(96,165,250,0.3)',
    borderRadius: 8,
    padding: '8px 16px',
    fontSize: 12,
    fontWeight: 700,
    cursor: downloading ? 'not-allowed' : 'pointer',
    whiteSpace: 'nowrap',
    transition: 'all 0.15s ease',
    opacity: downloading ? 0.7 : 1,
  };

  const progressBar = {
    height: 4,
    background: 'rgba(255,255,255,0.06)',
    borderRadius: 2,
    marginTop: 10,
    overflow: 'hidden',
  };

  const progressFill = {
    height: '100%',
    background: 'linear-gradient(90deg, #60A5FA, #36BDF0)',
    borderRadius: 2,
    transition: 'width 0.3s ease',
    width: `${downloadProgress}%`,
  };

  // Extract stats from cache data
  const symbolCount = cacheStatus?.total_symbols ?? cacheStatus?.symbols_cached ?? cacheStatus?.count ?? 0;
  const lastRefresh = cacheStatus?.last_refresh ?? cacheStatus?.last_updated ?? cacheStatus?.updated_at ?? null;
  const diskBytes = cacheStatus?.disk_usage_bytes ?? cacheStatus?.total_size ?? cacheStatus?.cache_size ?? 0;
  const regions = cacheStatus?.regions ?? cacheStatus?.region_count ?? 0;

  if (loading) {
    return (
      <div style={panel}>
        <div style={heading}>
          <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4" />
            <polyline points="7 10 12 15 17 10" />
            <line x1="12" y1="15" x2="12" y2="3" />
          </svg>
          Market Data Cache
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, color: '#8B949E', fontSize: 13 }}>
          <span style={{ width: 14, height: 14, border: '2px solid #60A5FA', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }} />
          Loading cache status...
        </div>
      </div>
    );
  }

  return (
    <div style={panel}>
      <div style={heading}>
        <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
          <path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4" />
          <polyline points="7 10 12 15 17 10" />
          <line x1="12" y1="15" x2="12" y2="3" />
        </svg>
        Market Data Cache
        <button
          onClick={fetchCacheStatus}
          title="Refresh cache status"
          style={{
            marginLeft: 'auto', background: 'none', border: 'none', cursor: 'pointer',
            color: '#8B949E', padding: 4, display: 'flex', alignItems: 'center',
          }}
        >
          <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <polyline points="23 4 23 10 17 10" />
            <polyline points="1 20 1 14 7 14" />
            <path d="M3.51 9a9 9 0 0114.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0020.49 15" />
          </svg>
        </button>
      </div>

      {/* Stats grid */}
      <div style={statGrid}>
        <div style={statCard}>
          <span style={statLabel}>Symbols Cached</span>
          <span style={statValue}>{symbolCount}</span>
        </div>
        <div style={statCard}>
          <span style={statLabel}>Disk Usage</span>
          <span style={statValue}>{formatBytes(diskBytes)}</span>
        </div>
        <div style={statCard}>
          <span style={statLabel}>Last Refresh</span>
          <span style={{ ...statValue, fontSize: 14, color: freshnessColor(lastRefresh) }}>
            {timeAgo(lastRefresh)}
          </span>
        </div>
        {regions > 0 && (
          <div style={statCard}>
            <span style={statLabel}>Regions</span>
            <span style={statValue}>{regions}</span>
          </div>
        )}
      </div>

      {/* Download input */}
      <div style={{ fontSize: 12, color: '#8B949E', marginBottom: 6 }}>
        Add symbols to cache (comma-separated):
      </div>
      <div style={inputRow}>
        <input
          type="text"
          value={symbolInput}
          onChange={(e) => setSymbolInput(e.target.value)}
          placeholder="AAPL, MSFT, TSLA..."
          style={input}
          disabled={downloading}
          onKeyDown={(e) => { if (e.key === 'Enter') handleDownload(); }}
        />
        <button
          onClick={handleDownload}
          disabled={downloading}
          style={btn}
        >
          {downloading ? 'Downloading...' : 'Download'}
        </button>
      </div>

      {/* Progress bar */}
      {downloading && (
        <>
          <div style={progressBar}>
            <div style={progressFill} />
          </div>
          <div style={{ fontSize: 11, color: '#8B949E', marginTop: 6, fontFamily: "'JetBrains Mono', monospace" }}>
            {downloadSymbol && `Downloading ${downloadSymbol}...`} {downloadProgress}%
          </div>
        </>
      )}

      {/* Error */}
      {error && (
        <div style={{
          marginTop: 10, padding: '8px 12px', borderRadius: 6,
          background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)',
          color: '#EF4444', fontSize: 12,
        }}>
          {error}
        </div>
      )}

      {/* Success */}
      {success && (
        <div style={{
          marginTop: 10, padding: '8px 12px', borderRadius: 6,
          background: 'rgba(34,197,94,0.1)', border: '1px solid rgba(34,197,94,0.2)',
          color: '#22C55E', fontSize: 12,
        }}>
          {success}
        </div>
      )}
    </div>
  );
}
